import{_ as e,o as a,c as i,a0 as r}from"./chunks/framework.NWv86GGy.js";const u=JSON.parse('{"title":"Spain — Country Profile","description":"Comprehensive guide to Spain for transgender relocation: legal recognition (Ley Trans), healthcare, cost of living, visa pathways, community, and risks.","frontmatter":{"layout":"doc","title":"Spain — Country Profile","description":"Comprehensive guide to Spain for transgender relocation: legal recognition (Ley Trans), healthcare, cost of living, visa pathways, community, and risks."},"headers":[],"relativePath":"countries/spain/index.md","filePath":"countries/spain/index.md","lastUpdated":1780601195000}'),o={name:"countries/spain/index.md"};function n(s,t,l,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="🇪🇸-spain" tabindex="-1"><span style="color:#c60b1e;">🇪🇸 Spain</span> <a class="header-anchor" href="#🇪🇸-spain" aria-label="Permalink to &quot;&lt;span style=&quot;color: #c60b1e;&quot;&gt;🇪🇸 Spain&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Madrid</td></tr><tr><td><strong>Population</strong></td><td>~47 million</td></tr><tr><td><strong>Language</strong></td><td>Spanish (Catalan, Basque, Galician in some regions)</td></tr><tr><td><strong>Currency</strong></td><td>Euro (EUR)</td></tr><tr><td><strong>EU Member</strong></td><td>Yes</td></tr><tr><td><strong>Equaldex Score</strong></td><td>89</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>4/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><p>Spain passed its landmark <strong>Ley Trans (Law 3/2023)</strong> in early 2023, making self-ID legal for all adults. The law was controversial within feminist and political circles but significantly improved the legal framework.</p><ul><li><strong>Gender Recognition:</strong> Self-ID since Law 3/2023. Adults 16+ can self-declare at the Registro Civil. 14–16 with parental consent, 12–14 with judicial approval. No medical requirements, no surgery, no therapy, no court order. Process takes 3–6 months.</li><li><strong>Anti-Discrimination Law:</strong> Comprehensive. Gender identity is protected in employment, housing, and services. The 2023 law specifically strengthens protections.</li><li><strong>Hate Crime Laws:</strong> Gender identity included in the criminal code (Article 22.4, aggravated by discriminatory motives).</li><li><strong>Same-Sex Marriage:</strong> Legal since 2005 (third country in the world).</li><li><strong>Conversion Therapy:</strong> Banned (Law 3/2023 explicitly prohibits it).</li></ul><h3 id="key-laws" tabindex="-1">Key Laws <a class="header-anchor" href="#key-laws" aria-label="Permalink to &quot;Key Laws&quot;">​</a></h3><ul><li>Law 3/2023 (Ley Trans): Self-declaration, conversion therapy ban, anti-discrimination</li><li>Law 13/2005 (Same-Sex Marriage)</li><li>Criminal Code Article 22.4 (Hate crimes)</li></ul><h2 id="healthcare-reality" tabindex="-1">Healthcare Reality <a class="header-anchor" href="#healthcare-reality" aria-label="Permalink to &quot;Healthcare Reality&quot;">​</a></h2><h3 id="gender-affirming-care" tabindex="-1">Gender-Affirming Care <a class="header-anchor" href="#gender-affirming-care" aria-label="Permalink to &quot;Gender-Affirming Care&quot;">​</a></h3><p>Spain&#39;s public healthcare system (SNS) covers gender-affirming care, but coverage varies significantly by autonomous community (region).</p><ul><li><strong>HRT Access:</strong> Informed consent available in many regions, but some areas still gatekeep. Madrid, Catalonia, Basque Country, and Valencia have good access. Andalusia and rural areas are more variable.</li><li><strong>HRT Cost:</strong> Minimal on public system (€4–10 co-pay per prescription). €30–60/month private.</li><li><strong>Endocrinologist Wait Times:</strong> 2–6 months on public system in major cities. 1–3 weeks private.</li><li><strong>Gender-Affirming Surgeries:</strong> Covered by SNS but wait times are long (1–3 years). Private options at €6,000–20,000.</li><li><strong>Regional Variation:</strong> Catalonia and Basque Country have dedicated trans health units. Some regions (e.g., Extremadura, Castilla-La Mancha) have no specialised services, requiring travel.</li></ul><h3 id="trans-friendly-clinics" tabindex="-1">Trans-Friendly Clinics <a class="header-anchor" href="#trans-friendly-clinics" aria-label="Permalink to &quot;Trans-Friendly Clinics&quot;">​</a></h3><ul><li><strong>Madrid:</strong> Hospital Ramón y Cajal, Hospital Clínico San Carlos, Fundación Triángulo (support)</li><li><strong>Barcelona:</strong> Hospital Clínic (Unitat de Trastorns d&#39;Identitat de Gènere), Hospital de Bellvitge, Cogam (LGBTQ+ centre)</li><li><strong>Valencia:</strong> Hospital La Fe, Lambda (LGBTQ+ organisation)</li><li><strong>Bilbao:</strong> Hospital de Basurto, Errespetuz (trans support group)</li><li><strong>Seville:</strong> Hospital Virgen del Rocío, limited trans services</li></ul><h2 id="where-to-live" tabindex="-1">Where to Live <a class="header-anchor" href="#where-to-live" aria-label="Permalink to &quot;Where to Live&quot;">​</a></h2><h3 id="tier-1-best-for-trans-migrants" tabindex="-1">Tier 1: Best for Trans Migrants <a class="header-anchor" href="#tier-1-best-for-trans-migrants" aria-label="Permalink to &quot;Tier 1: Best for Trans Migrants&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>Trans Community</th><th>HRT Access</th><th>Safety</th><th>Monthly Budget</th></tr></thead><tbody><tr><td><strong>Madrid</strong></td><td>Large, very active</td><td>Excellent (informed consent common)</td><td>Very good</td><td>€1,500–2,500</td></tr><tr><td><strong>Barcelona</strong></td><td>Large, very active</td><td>Excellent (informed consent common)</td><td>Very good</td><td>€1,600–2,600</td></tr><tr><td><strong>Valencia</strong></td><td>Medium-large</td><td>Good</td><td>Excellent</td><td>€1,300–2,000</td></tr><tr><td><strong>Bilbao</strong></td><td>Medium</td><td>Good</td><td>Excellent</td><td>€1,400–2,100</td></tr></tbody></table><h3 id="tier-2-moderate-options" tabindex="-1">Tier 2: Moderate Options <a class="header-anchor" href="#tier-2-moderate-options" aria-label="Permalink to &quot;Tier 2: Moderate Options&quot;">​</a></h3><ul><li><strong>Seville:</strong> Smaller scene, progressive for Andalusia, hot climate</li><li><strong>Palma de Mallorca:</strong> Small trans community but beautiful location</li><li><strong>Las Palmas (Gran Canaria):</strong> Small scene, popular with LGBTQ+ tourists</li></ul><h3 id="areas-to-be-cautious-in" tabindex="-1">Areas to Be Cautious In <a class="header-anchor" href="#areas-to-be-cautious-in" aria-label="Permalink to &quot;Areas to Be Cautious In&quot;">​</a></h3><ul><li><strong>Rural Andalusia:</strong> More conservative. Limited healthcare access. Lower social acceptance.</li><li><strong>Rural Castilla-La Mancha:</strong> Very conservative. Limited trans community.</li><li><strong>Small towns in Extremadura, Aragon, and Galicia:</strong> Limited or no trans-specific resources.</li></ul><h2 id="cost-of-living-reality" tabindex="-1">Cost of Living Reality <a class="header-anchor" href="#cost-of-living-reality" aria-label="Permalink to &quot;Cost of Living Reality&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Madrid</th><th>Barcelona</th><th>Valencia</th></tr></thead><tbody><tr><td>1-bedroom apartment</td><td>€900–1,500</td><td>€950–1,600</td><td>€700–1,100</td></tr><tr><td>Monthly HRT (public)</td><td>€4–10</td><td>€4–10</td><td>€4–10</td></tr><tr><td>Monthly HRT (private)</td><td>€30–60</td><td>€30–60</td><td>€30–60</td></tr><tr><td>Groceries</td><td>€250–400</td><td>€250–420</td><td>€200–350</td></tr><tr><td>Public transport</td><td>€30–50</td><td>€40–60</td><td>€25–40</td></tr><tr><td><strong>Rough monthly budget</strong></td><td><strong>€1,500–2,500</strong></td><td><strong>€1,600–2,600</strong></td><td><strong>€1,200–1,800</strong></td></tr></tbody></table><h3 id="savings-target-for-moving" tabindex="-1">Savings Target for Moving <a class="header-anchor" href="#savings-target-for-moving" aria-label="Permalink to &quot;Savings Target for Moving&quot;">​</a></h3><ul><li><strong>Estimated upfront cost:</strong> €4,500–8,000 <ul><li>Visa fees: €80–160</li><li>First/last month rent: €1,600–3,200</li><li>Flights: €400–1,000</li><li>Initial living costs (3 months): €3,000–5,000</li></ul></li></ul><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Visa Type</th><th>Income Requirement</th><th>Processing Time</th><th>Leads to PR?</th><th>Notes</th></tr></thead><tbody><tr><td>Digital Nomad Visa</td><td>€2,646/month minimum (2024)</td><td>1–3 months</td><td>Yes (renewable)</td><td>For remote workers; new since 2023</td></tr><tr><td>Work Visa</td><td>Job offer required</td><td>2–4 months</td><td>Yes</td><td>EU Blue Card available</td></tr><tr><td>Student Visa</td><td>Proof of funds</td><td>1–3 months</td><td>Yes (after graduation + work)</td><td>For full-time study</td></tr><tr><td>Non-Lucrative Visa</td><td>€28,800+/year</td><td>2–4 months</td><td>Yes</td><td>For people with savings/passive income (no work allowed)</td></tr><tr><td>EU Freedom of Movement</td><td>N/A</td><td>Immediate</td><td>Yes</td><td>For EU/EEA citizens</td></tr><tr><td>Asylum</td><td>N/A</td><td>6–24 months</td><td>Yes</td><td>Moderate grant rates (~45–60%)</td></tr></tbody></table><h3 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h3><ul><li>Spain&#39;s <strong>Digital Nomad Visa</strong> (2023) is one of Europe&#39;s most accessible, but it is new and some consulates have inconsistent processing.</li><li>The <strong>Non-Lucrative Visa</strong> allows residence without working. You must prove sufficient savings or passive income. Cannot convert to a work visa from within Spain.</li><li><strong>Empadronamiento</strong> (municipal registration) is needed for healthcare, school enrolment, and some other services.</li></ul><h2 id="community-and-visibility" tabindex="-1">Community and Visibility <a class="header-anchor" href="#community-and-visibility" aria-label="Permalink to &quot;Community and Visibility&quot;">​</a></h2><ul><li><strong>Trans community:</strong> Large and well-organised. FELGTBI+ (statewide federation), Fundación Triángulo, Cogam (Madrid), Casal Lambda (Barcelona), Chrysallis (families of trans youth).</li><li><strong>LGBTQ+ spaces:</strong> Madrid&#39;s Chueca district is one of Europe&#39;s most famous queer neighbourhoods. Barcelona&#39;s Eixample (Gaixample) district. Valencia&#39;s Russafa area.</li><li><strong>Social acceptance:</strong> Very high in major cities. Pride in Madrid (Orgullo) is one of the largest in the world with over 1 million participants.</li><li><strong>Dating pool:</strong> Large. Apps like Tinder, Grindr, Lex, and Wapo are commonly used.</li></ul><h2 id="what-the-equaldex-score-misses" tabindex="-1">What the Equaldex Score Misses <a class="header-anchor" href="#what-the-equaldex-score-misses" aria-label="Permalink to &quot;What the Equaldex Score Misses&quot;">​</a></h2><ul><li><strong>Regional variation</strong> is massive. Catalonia and Madrid are excellent; rural areas can be conservative and isolated.</li><li><strong>Healthcare access</strong> depends entirely on which region you register in. Some regions have dedicated trans health units; others have nothing.</li><li><strong>Economic reality:</strong> Spain&#39;s youth unemployment is high. Local salaries (€1,200–2,000/month gross) are much lower than northern Europe.</li><li><strong>Work culture:</strong> Siesta hours vary by region. Bureaucracy can be slow and paper-based.</li></ul><h2 id="quick-decision-checklist" tabindex="-1">Quick Decision Checklist <a class="header-anchor" href="#quick-decision-checklist" aria-label="Permalink to &quot;Quick Decision Checklist&quot;">​</a></h2><ul><li>[ ] Can you meet the income threshold for your visa type?</li><li>[ ] Are you settling in Madrid, Barcelona, Valencia, or Bilbao?</li><li>[ ] Are you willing to learn Spanish (B1 recommended)?</li><li>[ ] Do you have remote income or a clear work plan?</li></ul><p><strong>Spain offers excellent trans rights, a large and visible community, and good quality of life. The main barriers are low local salaries, regional variation in healthcare, and the need to learn Spanish.</strong></p><p><em>Sources: Gobierno de España (Ley Trans), FELGTBI+, TGEU, ILGA Europe, Equaldex, community reports. Last verified: June 2026.</em></p>',36)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
